INSERT IGNORE INTO role_permissions (role_id, permission_id)
SELECT r.id, p.id FROM roles r JOIN permissions p ON p.code IN ('business_directory.approve', 'business_directory.moderate')
WHERE r.name = 'ADMIN';

INSERT IGNORE INTO role_permissions (role_id, permission_id)
SELECT r.id, p.id FROM roles r JOIN permissions p ON p.code IN ('business_directory.register_own', 'business_directory.view')
WHERE r.name = 'MEMBER';

INSERT IGNORE INTO role_assignable_permissions (role_id, permission_id)
SELECT r.id, p.id FROM roles r JOIN permissions p ON p.code IN ('business_directory.approve', 'business_directory.moderate')
WHERE r.name = 'ADMIN';

INSERT IGNORE INTO role_assignable_permissions (role_id, permission_id)
